const upsertUserItemData = `-- name: UpsertUserItemData :exec
INSERT INTO user_item_data (user_id, item_id, playback_position_ticks, play_count, is_favorite, played, last_played_date)
VALUES ($1::uuid, $2::uuid,
        COALESCE($3::bigint, 0),
        COALESCE($4::int, 0),
        COALESCE($5::boolean, false),
        COALESCE($6::boolean, false),
        NOW())
ON CONFLICT (user_id, item_id) DO UPDATE SET
  playback_position_ticks = COALESCE($3::bigint, user_item_data.playback_position_ticks),
  play_count = COALESCE($4::int, user_item_data.play_count),
  is_favorite = COALESCE($5::boolean, user_item_data.is_favorite),
  played = COALESCE($6::boolean, user_item_data.played),
  last_played_date = NOW()
`

type UpsertUserItemDataParams struct {
	Column1    pgtype.UUID `json:"column_1"`
	Column2    pgtype.UUID `json:"column_2"`
	Position   pgtype.Int8 `json:"position"`
	PlayCount  pgtype.Int4 `json:"play_count"`
	IsFavorite pgtype.Bool `json:"is_favorite"`
	Played     pgtype.Bool `json:"played"`
}

func (q *Queries) UpsertUserItemData(ctx context.Context, arg UpsertUserItemDataParams) error {
	_, err := q.db.Exec(ctx, upsertUserItemData,
		arg.Column1,
		arg.Column2,
		arg.Position,
		arg.PlayCount,
		arg.IsFavorite,
		arg.Played,
	)
	return err
}

